Python<pre><code>from typing import List

from maize import BasePipeline, Item


class DataCleaningPipeline(BasePipeline):
    """数据清洗管道"""

    async def process_item(self, items: List[Item]) -&gt; bool:
        """清洗数据"""
        for item in items:
            # 去除标题前后空格
            if 'title' in item:
                item['title'] = item['title'].strip()

            # 价格转换为浮点数
            if 'price' in item:
                try:
                    # 去除价格中的非数字字符
                    price_str = ''.join(c for c in item['price'] if c.isdigit() or c == '.')
                    item['price'] = float(price_str)
                except (ValueError, AttributeError):
                    item['price'] = 0.0

            # URL 标准化
            if 'url' in item:
                if not item['url'].startswith('http'):
                    item['url'] = 'http://' + item['url']

        return True
</code></pre>

