Python<pre><code>async def start_requests(self):
    """批量生成请求"""
    base_url = "http://www.example.com/page"

    for page in range(1, 101):
        yield Request(
            url=f"{base_url}/{page}",
            callback=self.parse,
            meta={'page': page}
        )
